function truncateForWebview(value: string, maxChars: number): { text: string; truncated: boolean } {
	if (value.length <= maxChars) {
		return { text: value, truncated: false };
	}

	return {
		text: `${value.slice(0, maxChars)}\n\n[output truncated]`,
		truncated: true,
	};
}

